def categorize_article(title, description):
    sports_terms = ["sport", "sports", "game", "match", "team", "player", "coach", "stadium", "olympics", "football", "basketball", "baseball", "soccer", "tennis", "golf", "racing"]
    business_terms = ["business", "finance", "market", "company", "stock", "economy", "trade", "bank", "investment", "money", "oil", "gas"]
    science_terms = ["science", "technology", "research", "discovery", "innovation", "computer", "internet", "artificial intelligence", "ai", "scientific"]
    world_terms = ["world", "international", "global", "nation", "country", "government", "politics", "war", "conflict", "election"]

    sports_score = sum(1 for term in sports_terms if term in (title.lower() + " " + description.lower()).lower())
    business_score = sum(1 for term in business_terms if term in (title.lower() + " " + description.lower()).lower())
    science_score = sum(1 for term in science_terms if term in (title.lower() + " " + description.lower()).lower())
    world_score = sum(1 for term in world_terms if term in (title.lower() + " " + description.lower()).lower())

    scores = {"Sports": sports_score, "Business": business_score, "Science/Technology": science_score, "World": world_score}
    category = max(scores, key=scores.get)
    return category

for article in filtered_articles:
    try:
        article["category"] = categorize_article(article.get("title", ""), article.get("description", ""))
