if sports_articles:
    longest_description_article = max(sports_articles, key=lambda x: len(x.get("description", "")))
    try:
        result = longest_description_article["title"]
    except Exception as e:
        result = ""
    print("__RESULT__:" + json.dumps(result))
else:
    print("__RESULT__: No sports articles found.")

